## Common patterns

### Quantity selector with constraints

Create a quantity input with minimum and maximum values:

```jsx live-dev
const App = () => {
  const [quantity, setQuantity] = useState<number>(1);
  const totalPrice = quantity * 29.99;

  return (
    <Stack direction="column" gap="400">
      <Stack direction="column" gap="200">
        <Text fontWeight="semibold">Select Quantity</Text>
        <NumberInput
          value={quantity}
          onChange={(value) => setQuantity(value ?? 1)}
          minValue={1}
          maxValue={10}
          step={1}
        />
        <Text fontSize="sm" color="neutral.11">
          Minimum: 1, Maximum: 10
        </Text>
      </Stack>
      <Stack direction="row" justifyContent="space-between" alignItems="center">
        <Text>Total:</Text>
        <Text fontWeight="bold" fontSize="lg">
          ${totalPrice.toFixed(2)}
        </Text>
      </Stack>
    </Stack>
  );
}
```

### Measurement input with units

Create inputs for measurements with unit labels displayed as trailing elements:

```jsx live-dev
const App = () => {
  const [weight, setWeight] = useState<number>(0);
  const [height, setHeight] = useState<number>(0);
  const bmi = weight && height ? (weight / Math.pow(height / 100, 2)).toFixed(1) : 0;

  return (
    <Stack direction="column" gap="600">
      <Stack direction="column" gap="300">
        <Text fontWeight="semibold">Weight</Text>
        <NumberInput
          value={weight}
          onChange={(value) => setWeight(value ?? 0)}
          placeholder="0"
          minValue={0}
          maxValue={300}
          step={0.1}
          trailingElement={<Text fontSize="sm" color="neutral.11">kg</Text>}
        />
      </Stack>

      <Stack direction="column" gap="300">
        <Text fontWeight="semibold">Height</Text>
        <NumberInput
          value={height}
          onChange={(value) => setHeight(value ?? 0)}
          placeholder="0"
          minValue={0}
          maxValue={250}
          step={1}
          trailingElement={<Text fontSize="sm" color="neutral.11">cm</Text>}
        />
      </Stack>

      {weight > 0 && height > 0 && (
        <Stack direction="row" justifyContent="space-between" alignItems="center">
          <Text>BMI:</Text>
          <Text fontWeight="bold" fontSize="lg">{bmi}</Text>
        </Stack>
      )}
    </Stack>
  );
}
```

## Testing your implementation

These examples demonstrate how to test your implementation when using NumberInput within your application. As the component's internal functionality is already tested by Nimbus, these patterns help you verify your integration and application-specific logic.

### Basic Rendering Tests

Verify the component renders with expected elements

```tsx
import { describe, it, expect, vi } from "vitest";
import { render, screen } from "@testing-library/react";
import userEvent from "@testing-library/user-event";
import { NumberInput, NimbusProvider } from "@commercetools/nimbus";

describe("NumberInput - Basic rendering", () => {
  it("renders input element", () => {
    render(
      <NimbusProvider>
        <NumberInput aria-label="Quantity" />
      </NimbusProvider>
    );

    const input = screen.getByRole("textbox", { name: /quantity/i });
    expect(input).toBeInTheDocument();
    expect(input.tagName).toBe("INPUT");
  });

  it("renders with placeholder text", () => {
    render(
      <NimbusProvider>
        <NumberInput placeholder="Enter quantity" aria-label="Quantity" />
      </NimbusProvider>
    );

    expect(screen.getByPlaceholderText(/enter quantity/i)).toBeInTheDocument();
  });

  it("renders increment and decrement buttons", () => {
    render(
      <NimbusProvider>
        <NumberInput aria-label="Quantity" />
      </NimbusProvider>
    );

    expect(
      screen.getByRole("button", { name: /increment/i })
    ).toBeInTheDocument();
    expect(
      screen.getByRole("button", { name: /decrement/i })
    ).toBeInTheDocument();
  });
});
```

### Interaction Tests

Test user interactions with the number input

```tsx
import { describe, it, expect, vi } from "vitest";
import { render, screen } from "@testing-library/react";
import userEvent from "@testing-library/user-event";
import { NumberInput, NimbusProvider } from "@commercetools/nimbus";

describe("NumberInput - Interactions", () => {
  it("handles typing numeric values", async () => {
    const user = userEvent.setup();
    render(
      <NimbusProvider>
        <NumberInput aria-label="Quantity" />
      </NimbusProvider>
    );

    const input = screen.getByRole("textbox");
    await user.type(input, "42");

    expect(input).toHaveValue("42");
  });

  it("calls onChange with numeric value", async () => {
    const user = userEvent.setup();
    const handleChange = vi.fn();
    render(
      <NimbusProvider>
        <NumberInput onChange={handleChange} aria-label="Quantity" />
      </NimbusProvider>
    );

    const input = screen.getByRole("textbox");
    await user.clear(input);
    await user.type(input, "10");
    // Blur the input to trigger onChange
    await user.tab();

    // NumberInput calls onChange with the numeric value after blur
    expect(handleChange).toHaveBeenCalled();
    expect(handleChange).toHaveBeenCalledWith(10);
  });

  /**
   * Note: React Aria's stepper buttons use pointer events that JSDOM doesn't
   * fully support. These tests use keyboard-based interactions (ArrowUp/ArrowDown)
   * which test the same onChange behavior through a different, equally valid
   * user interaction pattern. Storybook play functions should test actual
   * button clicks in a real browser environment.
   */
  it("handles increment via keyboard", async () => {
    const user = userEvent.setup();
    const handleChange = vi.fn();
    render(
      <NimbusProvider>
        <NumberInput
          defaultValue={5}
          onChange={handleChange}
          aria-label="Quantity"
        />
      </NimbusProvider>
    );

    const input = screen.getByRole("textbox");
    await user.click(input);
    await user.keyboard("{ArrowUp}");

    expect(handleChange).toHaveBeenCalledWith(6);
  });

  it("handles decrement via keyboard", async () => {
    const user = userEvent.setup();
    const handleChange = vi.fn();
    render(
      <NimbusProvider>
        <NumberInput
          defaultValue={5}
          onChange={handleChange}
          aria-label="Quantity"
        />
      </NimbusProvider>
    );

    const input = screen.getByRole("textbox");
    await user.click(input);
    await user.keyboard("{ArrowDown}");

    expect(handleChange).toHaveBeenCalledWith(4);
  });
});
```

### Testing Constraints

Verify minimum, maximum, and step constraints

```tsx
import { describe, it, expect, vi } from "vitest";
import { render, screen } from "@testing-library/react";
import userEvent from "@testing-library/user-event";
import { NumberInput, NimbusProvider } from "@commercetools/nimbus";

describe("NumberInput - Constraints", () => {
  it("respects minimum value", async () => {
    const user = userEvent.setup();
    const handleChange = vi.fn();
    render(
      <NimbusProvider>
        <NumberInput
          defaultValue={2}
          minValue={1}
          onChange={handleChange}
          aria-label="Quantity"
        />
      </NimbusProvider>
    );

    const input = screen.getByRole("textbox");
    await user.click(input);

    // Decrement once: 2 -> 1 (at minimum)
    await user.keyboard("{ArrowDown}");
    expect(handleChange).toHaveBeenCalledWith(1);

    // Try again - should stay at minimum
    await user.keyboard("{ArrowDown}");
    // Component still calls onChange but with the same minimum value
    expect(handleChange).toHaveBeenLastCalledWith(1);
  });

  it("respects maximum value", async () => {
    const user = userEvent.setup();
    const handleChange = vi.fn();
    render(
      <NimbusProvider>
        <NumberInput
          defaultValue={9}
          maxValue={10}
          onChange={handleChange}
          aria-label="Quantity"
        />
      </NimbusProvider>
    );

    const input = screen.getByRole("textbox");
    await user.click(input);

    // Increment once: 9 -> 10 (at maximum)
    await user.keyboard("{ArrowUp}");
    expect(handleChange).toHaveBeenCalledWith(10);

    // Try again - should stay at maximum
    await user.keyboard("{ArrowUp}");
    // Component still calls onChange but with the same maximum value
    expect(handleChange).toHaveBeenLastCalledWith(10);
  });

  it("increments by step amount", async () => {
    const user = userEvent.setup();
    const handleChange = vi.fn();
    render(
      <NimbusProvider>
        <NumberInput
          defaultValue={0}
          step={5}
          onChange={handleChange}
          aria-label="Quantity"
        />
      </NimbusProvider>
    );

    const input = screen.getByRole("textbox");
    await user.click(input);
    await user.keyboard("{ArrowUp}");

    expect(handleChange).toHaveBeenCalledWith(5);
  });
});
```

